VALUES
  ('pukao-7c4986e7-moex-00097', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-113-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '甲公司發行普通股與特別股，普通股與特別股之額定股數分別為280,000股與10,000股，普通股 與特別股之每股面額分別為$10與$100；特別股為累積特別股，且特別股之股利率為6%。於X2 年12月31日，已發行且流通在外之普通股為238,000股；已發行且流通在外之特別股為10,000 股，另積欠股利為2年。X2年度，甲公司之淨利為$280,000；假設宣告現金股利為以下兩種情況， 情況一：宣告現金股利$80,000，情況二：宣告現金股利$210,000。以下何者為正確？', '["情況一下普通股與特別股之現金股利分別為$0與$80,000", "情況一下普通股與特別股之現金股利分別為$20,000與$60,000", "情況二下普通股與特別股之現金股利分別為$90,000與$120,000", "情況二下普通股與特別股之現金股利分別為$150,000與$60,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:45+00:00", "source_pdf_sha1": "20780e87fbd7", "answer_pdf_sha1": "849168fab101", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "417", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00098', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-113-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '甲公司之應收帳款係採用預期信用損失之估計方法，X1 年 12 月 31 日之應收帳款總額與備抵損 失分別為$300,000 與$21,000，X2 年 12 月 31 日之應收帳款總額與備抵損失分別為$500,000 與 $45,000。另外，甲公司 X2 年度之銷貨收入為$2,000,000 且均為賒銷，另預期信用減損損失為 $30,000。甲公司以直接法編製X2年度現金流量表時，自客戶之現金收取金額為何？', '["$1,770,000", "$1,794,000", "$1,800,000", "$2,146,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:45+00:00", "source_pdf_sha1": "20780e87fbd7", "answer_pdf_sha1": "849168fab101", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "417", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00099', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-113-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '甲公司X2年度之銷貨淨額為$4,800,000，且毛利率為40%；計算年度相關財務比率係以360天為 基準。甲公司X1年與X2年資產負債表中之部分項目金額如下： 財務報表金額 X1年12月31日 X2年12月31日 應收帳款 $350,000 $450,000 存貨 150,000 90,000 應付帳款 88,000 100,000 請問甲公司X2年度之淨營業週期為何？', '["30天", "33天", "45天", "57天"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:45+00:00", "source_pdf_sha1": "20780e87fbd7", "answer_pdf_sha1": "849168fab101", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "417", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00100', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-113-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '有關財務報表的資訊皆具備攸關性與忠實表述兩項基本品質特性時，則可藉由強化品質特性提供 協助選擇，下列何者非為強化性品質特性？', '["可比性", "可驗證性", "中立性", "可了解性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:45+00:00", "source_pdf_sha1": "20780e87fbd7", "answer_pdf_sha1": "849168fab101", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "417", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00101', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-113-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '甲公司被同業控告侵犯專利權，並要求賠償，甲公司的法律顧問評估甲公司很有可能敗訴，可能 的賠償金額在$1,000,000至$5,000,000之間，其機率分布如下： 金 額 機率 $1,500,000 10% $3,500,000 85% $5,000,000 5% 則甲公司有關該訴訟之會計處理為何？', '["應認列負債準備$3,375,000", "應認列負債準備$1,000,000 並附註揭露或有負債$3,500,000", "應認列負債準備$3,500,000", "僅附註揭露或有負債金額為$1,000,000至$5,000,000 41730"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:45+00:00", "source_pdf_sha1": "20780e87fbd7", "answer_pdf_sha1": "849168fab101", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "417", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00102', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-113-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '下列有關國際財務報導準則之敘述何者錯誤？', '["國際財務報導準則各號IFRS準則之內容包含生效日規定", "國際財務報導準則各號IFRS準則之內容包含過渡規定", "國際財務報導準則各號IFRS準則之內容包含應用指引", "國際財務報導準則各號IFRS準則之內容包含釋例"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:45+00:00", "source_pdf_sha1": "20780e87fbd7", "answer_pdf_sha1": "849168fab101", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "417", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00103', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-113-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '乙公司於 X9 年 6 月 17 日溢價發行轉換價格＄50 的可轉債，發行價格為$99,000，債券面額為 $85,000，是日相同條件但不可轉換的公司債其公允價值為$87,000。10 月初乙公司的股價上漲到 $70，該公司普通股面額為$10，可轉債持有人全部將可轉債轉換為乙公司的股票，下列轉換日相 關分錄何者正確？', '["貸方：普通股股本$17,600", "借方：應付公司債$99,000", "借方：資本公積-認股權$11,000", "貸方：資本公積-普通股發行溢價 $82,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:45+00:00", "source_pdf_sha1": "20780e87fbd7", "answer_pdf_sha1": "849168fab101", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "417", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00104', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-113-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '甲公司權益在X4年1月1日有普通股股本$1,000,00（0 每股面額$10），資本公積-發行溢價$200,000 及保留盈餘$600,000。當年4月1日以每股$20買回庫藏股8,000 股，於同年8月1日以每股$23 出售庫藏股 3,500 股，同年10月1日以每股$17出售庫藏股4,000 股，同年12月1日將其餘庫 藏股註銷，請問註銷後甲公司的保留盈餘總額為何？', '["$600,000", "$598,500", "$577,500", "$594,500"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:45+00:00", "source_pdf_sha1": "20780e87fbd7", "answer_pdf_sha1": "849168fab101", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "417", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00105', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-113-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', 'A公司X4年度銷貨收入$10,000，銷貨成本$8,800；期初應收帳款$600、期初存貨$640、期初應 付帳款$3,800；期末各科目餘額分別為應收帳款$880、存貨$720、應付帳款$3,920；則本期支付供 應商貨款金額是多少？', '["$9,000", "$8,760", "$8,560", "$8,880"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:45+00:00", "source_pdf_sha1": "20780e87fbd7", "answer_pdf_sha1": "849168fab101", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "417", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00106', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-113-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '甲公司於X4年1月1日流通在外普通股 72,000股，X4年間普通股之交易如下： 2月1日進行 每股分割為3股之股票分割； 4月1日發放20%股票股利；6月1日發行普通股 12,000股； 10 月1日買回庫藏股票 19,200股。該年度甲公司淨利$1,000,000，累積特別股100,000股，每股股 利1元，請問X4年度甲公司的基本每股盈餘約為多少？ （每股盈餘計算至小數點第二位）', '["$3.25", "$2.44", "$3.44", "$4.43"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:45+00:00", "source_pdf_sha1": "20780e87fbd7", "answer_pdf_sha1": "849168fab101", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "417", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL)
